#!/bin/bash\n# =============================================================\n# check-prisma-patterns.sh\n#\n# Enforces a few good Prisma patterns:\n# - No `$queryRaw` or `$executeRaw` to encourage type-safe queries.\n# - No `include` or `select` in `update` or `delete` operations.\n# =============================================================\n\nERRORS=0\nAPI_DIR=\"src/pages/api\"\n\nif [ ! -d \"$API_DIR\" ]; then\n  echo \"  ⚠️  Directory $API_DIR not found, skipping.\"\n  exit 0\nfi\n\n# 1. Check for raw SQL queries\nRAW_SQL_FILES=$(grep -l -E \'prisma\\.\\$queryRaw|prisma\\.\\$executeRaw\' $(find $API_DIR -type f -name \"*.ts\") || [[ $? == 1 ]])\n\nif [ ! -z \"$RAW_SQL_FILES\" ]; then\n  echo \"  ❌ Files found with raw SQL queries. Use the type-safe Prisma Client instead.\"\n  for file in $RAW_SQL_FILES; do\n    echo \"     - $file\"\n  done\n  ERRORS=$((ERRORS + 1))\nfi\n\n# 2. Check for `include` or `select` in `update` or `delete`\nUPDATE_DELETE_FILES=$(grep -l -E \'\\.update\\(|\\.delete\\(\' $(find $API_DIR -type f -name \"*.ts\") | xargs grep -l -E \'include:|select:\' || [[ $? == 1 ]])\n\nif [ ! -z \"$UPDATE_DELETE_FILES\" ]; then\n  echo \"  ❌ Files found with \`include\` or \`select\` in \`update\` or \`delete\` operations. Separate your read and write queries.\"\n  for file in $UPDATE_DELETE_FILES; do\n    echo \"     - $file\"\n  done\n  ERRORS=$((ERRORS + 1))\nfi\n\nif [ $ERRORS -eq 0 ]; then\n  echo \"  ✅ Prisma patterns are looking good.\"\n  exit 0\nelse\n  exit 1\nfi\n